import { useLocation } from "react-router-dom"
import "./profile.css"
export const Profile = () => {
    const location = useLocation()
    const [allUsers, currentUser] = location.state
  return (
      <div className="profile">
        <h1>Profile</h1>
        <p>{currentUser.userName}</p>
        <h1>All  Users</h1>
        {allUsers.map((user)=> (
            <p>{user.userName}</p>
        ))}
    </div>
  )
}
